/**
 * Query key factories for TanStack Query.
 *
 * Rules:
 *  - Always call the factory function — never inline the array literal.
 *  - Use the narrowest key that uniquely identifies the data when querying.
 *  - Use prefix forms (fewer params) for invalidation so all variants are cleared.
 *
 * Leave-management keys live in leaveHooks.ts as `leaveQueryKeys` (already a factory).
 */
export const queryKeys = {
  // ── Infrastructure ───────────────────────────────────────────────────────────
  health: () => ['api-health'] as const,
  about: () => ['api-about'] as const,

  // ── Auth ─────────────────────────────────────────────────────────────────────
  passwordPolicy: () => ['password-policy'] as const,

  // ── Customers ────────────────────────────────────────────────────────────────
  customers: {
    all: () => ['customers'] as const,
    projects: (customerId: string) => ['customers', customerId, 'projects'] as const,
  },

  // ── Projects / Assignments ────────────────────────────────────────────────────
  projects: {
    all: () => ['projects'] as const,
    assignments: (projectId: string) => ['projects', projectId, 'assignments'] as const,
  },
  employees: () => ['employees'] as const,

  // ── Work Schedule ─────────────────────────────────────────────────────────────
  workSchedule: {
    /** Full key — use for queries. */
    schedule: (year: number, month: number, isAdmin: boolean) =>
      ['work-schedule', year, month, isAdmin] as const,
    /** Prefix — use for invalidation to clear both admin and non-admin views. */
    scheduleMonth: (year: number, month: number) =>
      ['work-schedule', year, month] as const,
    /** Per-user schedule (admin view). */
    userSchedule: (userId: string, year: number, month: number) =>
      ['work-schedule', 'user', userId, year, month] as const,
    /** Home-page schedule data for a specific month (current user). */
    myMonth: (year: number, month: number) =>
      ['workSchedule', 'my', year, month] as const,
    /** Current user's month summaries. */
    monthsMy: () => ['work-schedule', 'months', 'my'] as const,
    /** Another user's month summaries. */
    monthsUser: (userId: string) =>
      ['work-schedule', 'months', 'user', userId] as const,
    /** Prefix — invalidates all month-summary variants. */
    monthsBase: () => ['work-schedule', 'months'] as const,
    /** Schedules awaiting approval. */
    pendingApproval: () => ['work-schedule', 'pending-approval'] as const,
  },

  // ── Extra Shifts ──────────────────────────────────────────────────────────────
  extraShifts: (year: number, month: number) =>
    ['extra-shifts', year, month] as const,

  // ── Public Holidays ───────────────────────────────────────────────────────────
  publicHolidays: {
    /** Flat list used by work-schedule views. */
    list: () => ['public-holidays'] as const,
    /** Home-page query filtered by year. */
    byYear: (year: number) => ['publicHolidays', year] as const,
    /** Full dataset for the Public Holidays admin page. */
    all: (viewMode: string, year: number) =>
      ['publicHolidaysAll', viewMode, year] as const,
    /** Prefix for invalidating all Public Holidays admin page entries. */
    allBase: () => ['publicHolidaysAll'] as const,
  },

  // ── Leave Balance (home page — separate from leaveQueryKeys) ─────────────────
  leaveBalance: (userId: string) => ['leaveBalance', userId] as const,
  leaveStats: () => ['leave-stats'] as const,

  // ── Leave Management internal lists ──────────────────────────────────────────
  leaveManagement: {
    employees: () => ['leave-management-employees'] as const,
    interns: () => ['leave-management-interns'] as const,
  },

  // ── Users / Admin ─────────────────────────────────────────────────────────────
  users: {
    employees: () => ['users', 'employee'] as const,
    interns: () => ['users', 'intern'] as const,
  },
  admin: {
    securitySummary: () => ['admin', 'security-summary'] as const,
    userDevices: (userId: string) => ['admin', 'user-devices', userId] as const,
  },

  // ── Team ─────────────────────────────────────────────────────────────────────
  teamMembers: () => ['team-members'] as const,

  // ── Roles ─────────────────────────────────────────────────────────────────────
  roles: {
    /** Base prefix — use for invalidation. */
    base: () => ['ht-roles'] as const,
    byId: (roleId: string) => ['role', roleId] as const,
    permissions: (roleId: string) => ['rolePermissions', roleId] as const,
    users: (roleId: string) => ['roleUsers', roleId] as const,
    list: (filterValues: unknown, sort: unknown, sortOrder: unknown, pageIndex: number, pageSize: number, search: string) =>
      ['ht-roles', filterValues, sort, sortOrder, pageIndex, pageSize, search] as const,
  },

  // ── Application Settings ──────────────────────────────────────────────────────
  appSettings: {
    /** Base prefix — use for invalidation. */
    base: () => ['ht-app-settings'] as const,
    list: (pageIndex: number, pageSize: number, search: string) =>
      ['ht-app-settings', pageIndex, pageSize, search] as const,
  },

  // ── Logs ──────────────────────────────────────────────────────────────────────
  logs: {
    list: (filterValues: unknown, sort: unknown, sortOrder: unknown, pageIndex: number, pageSize: number) =>
      ['ht-logs', filterValues, sort, sortOrder, pageIndex, pageSize] as const,
  },

  // ── Devices ──────────────────────────────────────────────────────────────────
  myDevices: () => ['my-devices'] as const,

  // ── Generic Grid ─────────────────────────────────────────────────────────────
  gridData: (endpoint: string, page: number, pageSize: number) =>
    ['gridData', endpoint, page, pageSize] as const,

  // ── Permissions ───────────────────────────────────────────────────────────────
  permissionsCatalog: () => ['all-permissions-catalog'] as const,
} as const;
